import scala.collection.mutable.ArrayBuffer

class UnionFind(size: Int) {
  private val parent = Array.tabulate(size)(i => i)
  private val rank = Array.fill(size)(0)

  def find(u: Int): Int = {
    if (parent(u) != u) {
      parent(u) = find(parent(u))
    }
    parent(u)
  }

  def union(u: Int, v: Int): Boolean = {
    val rootU = find(u)
    val rootV = find(v)
    if (rootU == rootV) return false

    if (rank(rootU) > rank(rootV)) {
      parent(rootV) = rootU
    } else if (rank(rootU) < rank(rootV)) {
      parent(rootU) = rootV
    } else {
      parent(rootV) = rootU
      rank(rootU) += 1
    }
    true
  }
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val sortedEdges = edges.sortBy(_(2))
  val uf = new UnionFind(n.toInt)
  var components = n.toInt
  var maxCost = 0L

  for (edge <- sortedEdges) {
    if (components <= k) return maxCost
    val u = edge(0).toInt
    val v = edge(1).toInt
    val w = edge(2)
    if (uf.find(u) != uf.find(v)) {
      uf.union(u, v)
      components -= 1
      maxCost = w
    }
  }

  maxCost
}
